import{_ as a,H as l,f as e,i as t}from"./chunks/framework.Cvt1eIE0.js";const o="/quote/images/member/index.png",r="/quote/images/member/add.png",n="/quote/images/member/add1.png",s="/quote/images/member/assign.png",_=JSON.parse('{"title":"成员和权限使用说明","description":"","frontmatter":{},"headers":[],"relativePath":"quote/bulk-data.md","filePath":"quote/bulk-data.md"}'),p={name:"quote/bulk-data.md"};function u(g,i,h,d,m,c){return l(),e("div",null,[...i[0]||(i[0]=[t('<h1 id="成员和权限使用说明" tabindex="-1">成员和权限使用说明 <a class="header-anchor" href="#成员和权限使用说明" aria-label="Permalink to &quot;成员和权限使用说明&quot;">​</a></h1><p>如果您的店铺有多位员工一起处理报价单，可使用 <strong>Members &amp; Permissions</strong> 功能，为不同成员分配各自的后台访问权限。</p><h2 id="_1-功能入口" tabindex="-1">1. 功能入口 <a class="header-anchor" href="#_1-功能入口" aria-label="Permalink to &quot;1. 功能入口&quot;">​</a></h2><p>进入应用后台左侧菜单：</p><ul><li><strong>Members &amp; Permissions</strong></li></ul><p><img src="'+o+'" alt="member"></p><p>在这里您可以：</p><ul><li>查看当前成员列表</li><li>新增成员</li><li>编辑成员资料</li><li>设置角色与状态</li><li>配置可访问页面与可执行操作</li><li>删除成员</li></ul><h2 id="_2-成员列表能看到什么" tabindex="-1">2. 成员列表能看到什么 <a class="header-anchor" href="#_2-成员列表能看到什么" aria-label="Permalink to &quot;2. 成员列表能看到什么&quot;">​</a></h2><p>在成员列表页，您可以看到每位成员的：</p><ul><li>姓名</li><li>邮箱</li><li>角色</li><li>已分配的报价数量</li><li>当前状态</li></ul><p>这适合用于快速确认团队成员是否已开通、是否还在使用，以及谁手上有多少报价任务。</p><h2 id="_3-如何新增成员" tabindex="-1">3. 如何新增成员 <a class="header-anchor" href="#_3-如何新增成员" aria-label="Permalink to &quot;3. 如何新增成员&quot;">​</a></h2><h3 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to &quot;操作步骤&quot;">​</a></h3><ol><li>进入 <strong>Members &amp; Permissions</strong></li><li>点击 <strong>Add Member</strong></li></ol><p><img src="'+r+'" alt="member"></p><ol><li>填写： <ul><li><strong>Name</strong></li><li><strong>Email</strong></li><li><strong>Role</strong></li><li><strong>Status</strong></li></ul></li></ol><p><img src="'+n+'" alt="member"></p><ol><li>如果角色不是 Admin，再继续勾选对应权限</li><li>保存</li></ol><h2 id="_4-角色说明" tabindex="-1">4. 角色说明 <a class="header-anchor" href="#_4-角色说明" aria-label="Permalink to &quot;4. 角色说明&quot;">​</a></h2><p>当前系统支持两种角色：</p><h3 id="admin" tabindex="-1">Admin <a class="header-anchor" href="#admin" aria-label="Permalink to &quot;Admin&quot;">​</a></h3><ul><li>自动拥有全部权限</li><li>不需要逐项勾选权限</li><li>适合店铺负责人或核心管理人员</li></ul><h2 id="_5-状态说明" tabindex="-1">5. 状态说明 <a class="header-anchor" href="#_5-状态说明" aria-label="Permalink to &quot;5. 状态说明&quot;">​</a></h2><p>每个成员都可以设置状态：</p><ul><li><strong>Active</strong>：成员可以正常使用分配给他的权限</li><li><strong>Inactive</strong>：成员保留资料，但不再作为正常活跃成员使用</li></ul><p>适用场景：</p><ul><li>员工离职但您暂时不想删除记录</li><li>临时停用某位成员的后台操作权限</li></ul><h2 id="_6-quote-权限说明" tabindex="-1">6. Quote 权限说明 <a class="header-anchor" href="#_6-quote-权限说明" aria-label="Permalink to &quot;6. Quote 权限说明&quot;">​</a></h2><p>当角色为 <strong>Member</strong> 时，您可以单独勾选报价相关权限。</p><h3 id="quote-权限包括" tabindex="-1">Quote 权限包括 <a class="header-anchor" href="#quote-权限包括" aria-label="Permalink to &quot;Quote 权限包括&quot;">​</a></h3><ul><li><p><strong>View Quote Detail</strong> 可以查看报价详情页</p></li><li><p><strong>Create Quote</strong> 可以在后台创建报价</p></li><li><p><strong>Update Quote Items</strong> 可以修改报价中的商品、数量、价格等内容</p></li><li><p><strong>Update Quote Message</strong> 可以在报价时间线中回复或更新消息</p></li><li><p><strong>Set Discount</strong> 可以设置折扣</p></li><li><p><strong>Set Shipping</strong> 可以设置运费</p></li><li><p><strong>Send Quote Invoice</strong> 可以发送报价 invoice</p></li><li><p><strong>Export Quotes Excel</strong> 可以导出报价列表</p></li><li><p><strong>Download Quote PDF</strong> 可以下载报价 PDF</p></li><li><p><strong>Cancel / Decline Quote</strong> 可以拒绝或取消报价</p></li><li><p><strong>Delete Quotes</strong> 可以删除报价</p></li><li><p><strong>Assign Quote Owners</strong> 可以给报价分配负责人</p></li></ul><h2 id="_7-navigation-权限说明" tabindex="-1">7. Navigation 权限说明 <a class="header-anchor" href="#_7-navigation-权限说明" aria-label="Permalink to &quot;7. Navigation 权限说明&quot;">​</a></h2><p>除了报价操作权限，还可以控制成员是否能进入某些后台菜单页面。</p><h3 id="navigation-权限包括" tabindex="-1">Navigation 权限包括 <a class="header-anchor" href="#navigation-权限包括" aria-label="Permalink to &quot;Navigation 权限包括&quot;">​</a></h3><ul><li><p><strong>Members Manage</strong> 可以进入成员管理页面</p></li><li><p><strong>Tiered Pricing Manage</strong> 可以进入阶梯定价页面</p></li><li><p><strong>Form Fields Manage</strong> 可以进入前台表单字段设置页面</p></li><li><p><strong>Appearance Manage</strong> 可以进入前台样式设置页面</p></li><li><p><strong>Settings Manage</strong> 可以进入系统设置页面</p></li></ul><h2 id="_8-编辑成员" tabindex="-1">8. 编辑成员 <a class="header-anchor" href="#_8-编辑成员" aria-label="Permalink to &quot;8. 编辑成员&quot;">​</a></h2><p>如果成员已经创建，您可以进入该成员详情页继续修改：</p><ul><li>姓名</li><li>邮箱</li><li>角色</li><li>状态</li><li>Quote 权限</li><li>Navigation 权限</li></ul><h3 id="注意" tabindex="-1">注意 <a class="header-anchor" href="#注意" aria-label="Permalink to &quot;注意&quot;">​</a></h3><ul><li>如果把角色改为 <strong>Admin</strong>，系统会自动赋予全部权限</li></ul><h2 id="_9-删除成员" tabindex="-1">9. 删除成员 <a class="header-anchor" href="#_9-删除成员" aria-label="Permalink to &quot;9. 删除成员&quot;">​</a></h2><p>在成员列表页中，您可以删除成员。</p><p>如果只是暂时停用，通常更建议先改为 <strong>Inactive</strong>，而不是直接删除。</p><h2 id="_10-报价分配与成员协作" tabindex="-1">10. 报价分配与成员协作 <a class="header-anchor" href="#_10-报价分配与成员协作" aria-label="Permalink to &quot;10. 报价分配与成员协作&quot;">​</a></h2><p>成员功能通常和报价分配一起使用。</p><p>在报价列表或报价详情中，如果您具备 <strong>Assign Member</strong> 权限，就可以把报价分配给某位成员。</p><p>这适合用于：</p><ul><li>销售团队按客户分单</li><li>客服团队按区域或品牌分单</li><li>多人协作处理不同报价任务</li></ul><p><img src="'+s+'" alt="member"></p><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><ul><li>Admin 会自动拥有全部权限</li><li>如果成员看不到某个页面，先检查是否分配了对应的 Navigation 权限</li><li>如果成员能进入页面但无法执行操作，先检查是否分配了对应的 Quote 权限</li></ul>',52)])])}const q=a(p,[["render",u]]);export{_ as __pageData,q as default};
